import pd from '../_classes/program-data';
import MetadataDTO from 'api/src/dto/metadata-dto';

export async function FileCard({ metadata }: { metadata: MetadataDTO }) {
  const response: Response = await fetch(`${pd.apiUrl}/api/files/${metadata.id}`);
  const bin: Blob = await response.blob();
  const image: string = URL.createObjectURL(bin);
  return (
    <div>
      <h3><a>{metadata.originalName}</a></h3>
      <img src={image} alt={metadata.originalName} />
      <p>Тип: {metadata.mime}</p>
      <p>Размер: {metadata.size}</p>
      <p>Создан: {metadata.createdAt}</p>
    </div>
  );
}